head.script:
/* ★AIcraft guide★    
스크립트 수작업 유의사항
*/




scwin.onpageload = function() {};

scwin.onpageunload = function() {};
scwin.Button1_OnClick = function(e) {
    //여기에 구현코드를 삽입하세요.
    //계산식
    if (fldExcessprogressiveFeeYN.getValue() == "!") {
        Link.lnkMgivstAcno = $c.iz.data.getParentData("AccountID.Data");
        Link.lnkFeeTranSerno = $c.iz.data.getParentData("cboInquiryGubn.Data");
        Link.lnkInquiryBaseYmd = $c.iz.data.getParentData("fldStartingYymmdd.Data");
        Link.lnkInquiryGubn = "2";
        $c.iz.screen.popup("KEC04N84001", "DATALINK");
    } else {
        $c.iz.data.message("계산식은 누진율방식일때만 해당됩니다.");
    }
};

scwin.Button2_OnClick = async function(e) {
    //여기에 구현코드를 삽입하세요.

    var cboInquiryGubn = $c.iz.data.getParentData("cboInquiryGubn.Data");
    var fldStartingYymmdd = $c.iz.data.getParentData("fldStartingYymmdd.Data");
    if (cboInquiryGubn == "1") {
        if (fldStartingYymmdd > $c.user.getUserProfile('tranBaseYmd')) {
            $c.iz.data.message("조회기준일자를  확인해 주십시요. 미래일자로는 조회가 불가합니다.");
            return;
        }
    } else if (cboInquiryGubn == "2") {
        if (fldPaymentScheduledYymmdd.getValue() == "") {
            $c.iz.data.message("납입예정일자 항목에 값이 입력되지 않았습니다.");
            return;
        } else if (fldPaymentScheduledBurdenAmount.getValue() == "") {
            $c.iz.data.message("납입예정부담금 항목에 값이 입력되지 않았습니다.");
            return;
        } else if (fldPaymentScheduledYymmdd.getValue() == "" && fldPaymentScheduledBurdenAmount.getValue() == "") {
            $c.iz.data.message("납입예정부담금 항목과 납입예정일자 항목에 값이 입력되지 않았습니다.");
            return;
        }
    }
    if (fldPaymentScheduledYymmdd.getValue() < $c.user.getUserProfile('tranBaseYmd')) {
        $c.iz.data.message("납입예정일자를 확인해 주십시요. 과거년월일로는 조회가 불가합니다.");
        return;
    }
    /**
    if(fldPaymentScheduledYymmdd.Data >= GetParentData("fldMgivstNewYmd.Data")){

    	Message("납입예정일자를 확인해 주십시요. 운용관리계약 응당일이전 날짜만 조회가 가능합니다.");	
    	return;

    }

    if(fldPaymentScheduledYymmdd.Data >= GetParentData("fldAssetNewYmd.Data")){

    	Message("납입예정일자를 확인해 주십시요. 자산관리계약 응당일이전 날짜만 조회가 가능합니다.");	
    	return;

    }
    **/
    if (fldPaymentScheduledBurdenAmount.getValue() == "0") {
        $c.iz.data.message("0원 보다 큰 금액을 입력해 주십시요.");
        return;
    }
    $c.iz.tran.setTranID("KEC04M8A42");
    await $c.iz.tran.ASend();
};

scwin.OnEndTran = function() {
    //여기에 구현코드를 삽입하세요.
    if ($c.iz._tran.tranId == "KEC04M8A42" && $c.iz._tran.bError == false) {
        var cboInquiryGubn = $c.iz.data.getParentData("cboInquiryGubn.Data");
        if (cboInquiryGubn == '2') {
            scwin.feeSumOfAmount();
            scwin.totalAmountOfPayment();
        }
    }
};


scwin.totalAmountOfPayment = function() {
    var feeSumOfAmount = 0;
    var scheduledBurdenAmount = 0;
    if (fldFeeSumOfAmount.getValue() != "") {
        feeSumOfAmount = fldFeeSumOfAmount.getValue();
    }
    if (fldPaymentScheduledBurdenAmount.getValue() != "") {
        scheduledBurdenAmount = fldPaymentScheduledBurdenAmount.getValue();
    }
    fldTotalAmountOfPayment.setValue(parseFloat(feeSumOfAmount) + parseFloat(scheduledBurdenAmount));
};

scwin.feeSumOfAmount = function() {
    var assetManagementFeeNum = 0;
    var managementForInvestmentManagementFeeNum = 0;
    if (fldAssetManagementFee.getValue() != "") {
        assetManagementFeeNum = fldAssetManagementFee.getValue();
    }
    if (fldManagementForInvestmentManagementFee.getValue() != "") {
        managementForInvestmentManagementFeeNum = fldManagementForInvestmentManagementFee.getValue();
    }
    fldFeeSumOfAmount.setValue(parseFloat(assetManagementFeeNum) + parseFloat(managementForInvestmentManagementFeeNum));
};
